"use client"

import React, { useEffect, useRef, useState } from 'react'

declare global {
  interface Window {
    kakao: any;
  }
}

interface Place {
  id: string;
  place_name: string;
  x: string;
  y: string;
}

const KAKAO_KEY = process.env.NEXT_PUBLIC_KAKAO_APP_KEY;

interface KakaoMapProps {
  pharmacies: Place[];
  // 🚀 수정: 저장 완료 후 중심 좌표(lat, lon)를 부모에게 전달
  onDataSaved?: (lat: number, lon: number) => void; 
}

export default function KakaoMap({ pharmacies, onDataSaved }: KakaoMapProps) {
  const mapContainer = useRef<HTMLDivElement>(null);
  const [mapInstance, setMapInstance] = useState<any>(null);
  const [showSearchBtn, setShowSearchBtn] = useState(false);
  const markersRef = useRef<any[]>([]);
  const infoWindowRef = useRef<any>(null);
  const isSearchStarted = useRef(false);

  useEffect(() => {
    if (!KAKAO_KEY) return;
    const script = document.createElement("script");
    script.src = `//dapi.kakao.com/v2/maps/sdk.js?appkey=${KAKAO_KEY}&autoload=false&libraries=services`;
    script.async = true;
    document.head.appendChild(script);

    script.onload = () => {
      window.kakao.maps.load(() => {
        if (!mapContainer.current) return;
        const options = { center: new window.kakao.maps.LatLng(37.566826, 126.9786567), level: 4 };
        const map = new window.kakao.maps.Map(mapContainer.current, options);
        infoWindowRef.current = new window.kakao.maps.InfoWindow({ zIndex: 1 });
        setMapInstance(map);

        // 🚀 지도를 움직이면 "현 위치에서 재검색" 버튼 표시
        window.kakao.maps.event.addListener(map, 'dragend', () => setShowSearchBtn(true));
      });
    };
  }, []);

  useEffect(() => {
    if (!mapInstance || isSearchStarted.current) return;
    if (navigator.geolocation) {
      isSearchStarted.current = true;
      navigator.geolocation.getCurrentPosition((pos) => {
        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;
        const locPosition = new window.kakao.maps.LatLng(lat, lon);
        mapInstance.setCenter(locPosition);
        searchAndSavePharmacies(mapInstance, locPosition);
      });
    }
  }, [mapInstance]);

  useEffect(() => {
    if (!mapInstance || !pharmacies) return;
    removeMarkers();
    pharmacies.forEach((place) => {
      const marker = new window.kakao.maps.Marker({
        position: new window.kakao.maps.LatLng(place.y, place.x),
        map: mapInstance
      });
      markersRef.current.push(marker);
      window.kakao.maps.event.addListener(marker, 'click', () => {
        const content = `<div style="padding:10px; font-size:12px;"><strong>${place.place_name}</strong><br/><a href="https://map.kakao.com/link/to/${place.place_name},${place.x},${place.y}" style="color:blue">상세보기</a></div>`;
        infoWindowRef.current.setContent(content);
        infoWindowRef.current.open(mapInstance, marker);
      });
    });
  }, [pharmacies, mapInstance]);

  // 🚀 버튼 클릭 시 실행될 재검색 함수
  const handleReSearch = () => {
    if (!mapInstance) return;
    const center = mapInstance.getCenter();
    searchAndSavePharmacies(mapInstance, center);
    setShowSearchBtn(false); // 버튼 숨기기
  };

  const searchAndSavePharmacies = (map: any, locPosition: any) => {
    const ps = new window.kakao.maps.services.Places();
    ps.categorySearch('PM9', async (data: any[], status: any) => {
      if (status === window.kakao.maps.services.Status.OK) {
        try {
          const response = await fetch('http://localhost:8080/api/pharmacy/save-kakao-data', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
          });

          if (response.ok && onDataSaved) {
            // 🚀 부모에게 현재 지도의 중심 좌표를 넘겨줌
            onDataSaved(locPosition.getLat(), locPosition.getLng());
          }
        } catch (error) {
          console.error("서버 통신 오류:", error);
        }
      }
    }, { location: locPosition, radius: 2000 });
  };

  const removeMarkers = () => {
    markersRef.current.forEach(m => m.setMap(null));
    markersRef.current = [];
    if (infoWindowRef.current) infoWindowRef.current.close();
  };

  return (
    <div style={{ position: 'relative', width: '100%', height: '100%' }}>
      <div ref={mapContainer} style={{ width: '100%', height: '100%', backgroundColor: '#eee' }} />
      {/* 🚀 재검색 버튼 UI */}
      {showSearchBtn && (
        <button 
          onClick={handleReSearch}
          style={{
            position: 'absolute', bottom: '20px', left: '50%', transform: 'translateX(-50%)',
            zIndex: 10, padding: '10px 20px', backgroundColor: '#3b82f6', color: 'white',
            border: 'none', borderRadius: '50px', cursor: 'pointer', fontWeight: 'bold',
            boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
          }}
        >
          🔄 이 지역에서 재검색
        </button>
      )}
    </div>
  );
}