"use client";

import { useState, useEffect, useCallback } from "react";
import KakaoMap from "@/components/map/KakaoMap";
import "./pharmacy.css";

interface Pharmacy {
  id: number;
  hpid: string;
  dutyName: string;
  dutyTel1: string;
  dutyAddr: string;
  wgs84Lon: string;
  wgs84Lat: string;
  qt: string;
}

export default function PharmacyPage() {
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  
  const [page, setPage] = useState(0); 
  const [totalPages, setTotalPages] = useState(0);
  const [totalElements, setTotalElements] = useState(0);

  const [userLocation, setUserLocation] = useState<{lat: number, lon: number} | null>(null);
  const [isLocationChecked, setIsLocationChecked] = useState(false);

  // 1. 내 위치 파악
  useEffect(() => {
    if (!navigator.geolocation) {
      setIsLocationChecked(true);
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setUserLocation({
          lat: pos.coords.latitude,
          lon: pos.coords.longitude
        });
        setIsLocationChecked(true);
      },
      (err) => {
        console.warn("위치 파악 실패:", err);
        setIsLocationChecked(true);
      }
    );
  }, []);

  // 2. DB 조회 함수
  const fetchPharmacies = useCallback(async (pageNum: number, location: {lat: number, lon: number} | null) => {
    try {
      setIsLoading(true);
      const url = new URL("http://localhost:8080/api/pharmacy/list");
      url.searchParams.append("page", pageNum.toString());
      url.searchParams.append("size", "20");
      
      if (location) {
        url.searchParams.append("lat", location.lat.toString());
        url.searchParams.append("lon", location.lon.toString());
      }

      const response = await fetch(url.toString());
      if (!response.ok) throw new Error("서버 응답 에러");
      
      const data = await response.json();
      setPharmacies(data.content);
      setTotalPages(data.totalPages);
      setTotalElements(data.totalElements);
    } catch (error) {
      console.error("로딩 실패:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // 초기 로딩 (위치 파악 후)
  useEffect(() => {
    if (isLocationChecked) {
      fetchPharmacies(page, userLocation);
    }
  }, [page, isLocationChecked, userLocation, fetchPharmacies]);

  // 3. 🚀 [추가] 지도가 데이터를 저장했다고 알리면 실행되는 함수
 // 🚀 수정: 데이터 저장 시 전달받은 새 좌표로 목록을 갱신함
  const handleDataSaved = (newLat: number, newLon: number) => {
    console.log("새 지역 데이터 저장 완료. 목록을 갱신합니다.");
    
    // 1. 현재 검색 위치 상태 업데이트 (리스트가 이 좌표를 기준으로 불러와짐)
    setUserLocation({ lat: newLat, lon: newLon });
    
    // 2. 페이지를 0으로 초기화하고 새 데이터를 불러옴
    setPage(0);
    fetchPharmacies(0, { lat: newLat, lon: newLon });
  };

  return (
    <div className="pharmacy-container">
      <div className="pharmacy-header">
        <h1 className="pharmacy-title">전국 약국 지도 🏥</h1>
        <p className="pharmacy-desc">
          우리 DB에서 관리하는 <strong>{totalElements.toLocaleString()}</strong>개의 약국 정보를 확인하세요.
        </p>
      </div>

      <div className="map-section">
        <KakaoMap 
          // DB 데이터를 지도에 전달 (마커 표시)
          pharmacies={pharmacies.map(p => ({
            id: p.hpid,
            place_name: p.dutyName,
            x: p.wgs84Lon,
            y: p.wgs84Lat
          }))}
          // 👇 이 콜백 함수를 전달해서 지도가 저장 완료하면 목록을 갱신하게 함
          onDataSaved={handleDataSaved} 
        />
      </div>

      <div className="pharmacy-list-section">
         {/* ... 리스트 및 페이지네이션 코드 (기존과 동일) ... */}
         {/* 기존 PharmacyPage.tsx의 하단 부분 그대로 유지하시면 됩니다 */}
         <div className="list-header">
           <h3>검색 결과 <span className="count">{pharmacies.length}</span>건</h3>
           <span className="page-info">({page + 1} / {totalPages} 페이지)</span>
         </div>

         {isLoading ? (
           <div className="loading-msg"><div className="spinner"></div>데이터 로드 중...</div>
         ) : (
           <>
             <div className="pharmacy-grid">
               {pharmacies.map((item) => (
                 <div key={item.hpid} className="pharmacy-card" onClick={() => window.open(`https://map.kakao.com/link/to/${item.dutyName},${item.wgs84Lat},${item.wgs84Lon}`)}>
                   <div className="card-body">
                     <h4 className="place-name">{item.dutyName}</h4>
                     <div className="info-row"><span className="label">주소</span><span className="value">{item.dutyAddr}</span></div>
                     <div className="info-row"><span className="label">전화</span><span className="value">{item.dutyTel1 || "번호 없음"}</span></div>
                   </div>
                 </div>
               ))}
             </div>
             <div className="pagination">
               <button className="page-btn" onClick={() => setPage(p => Math.max(0, p - 1))} disabled={page === 0}>이전</button>
               <div className="page-numbers"><strong>{page + 1}</strong> / {totalPages}</div>
               <button className="page-btn" onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))} disabled={page >= totalPages - 1}>다음</button>
             </div>
           </>
         )}
      </div>
    </div>
  );
} 